class BookMyShow {
    int n, m;
    int[] minEmptySeats; // min empty seats in each row
    int[] totalEmptySeats; // total empty seats in each row
    int[] seats; // seats in each row

    public BookMyShow(int n, int m) {
        this.n = n;
        this.m = m;
        minEmptySeats = new int[n];
        totalEmptySeats = new int[n];
        seats = new int[n];
        for (int i = 0; i < n; i++) {
            minEmptySeats[i] = m;
            totalEmptySeats[i] = m;
            seats[i] = 0;
        }
    }

    public int[] gather(int k, int maxRow) {
        for (int i = 0; i <= maxRow; i++) {
            if (totalEmptySeats[i] >= k) {
                int start = seats[i];
                int end = start + k - 1;
                if (end < m && minEmptySeats[i] >= k) {
                    seats[i] += k;
                    totalEmptySeats[i] -= k;
                    if (totalEmptySeats[i] == 0) minEmptySeats[i] = m;
                    else minEmptySeats[i] = m - seats[i];
                    return new int[] {i, start};
                }
            }
        }
        return new int[] {};
    }

    public boolean scatter(int k, int maxRow) {
        int total = 0;
        for (int i = 0; i <= maxRow; i++) {
            total += totalEmptySeats[i];
            if (total >= k) {
                for (int j = 0; j <= i; j++) {
                    int allocated = Math.min(k, totalEmptySeats[j]);
                    seats[j] += allocated;
                    totalEmptySeats[j] -= allocated;
                    k -= allocated;
                    minEmptySeats[j] = m - seats[j];
                }
                return true;
            }
        }
        return false;
    }
}

